const coerceToString = (v) => {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'object') {
    if (typeof v.text === 'string') return v.text;
    if (typeof v.output === 'string') return v.output;
    if (typeof v.response === 'string') return v.response;
    if (v.response && typeof v.response.text === 'string') return v.response.text;
  }
  return String(v);
};

const fallbackQuestion = 'Could you share a bit more detail about what happened with your order?';
const proofRequestQuestion = 'Please upload up to 2 photos showing the issue so I can continue reviewing your case.';

let raw = $json;
let data;

if (raw && typeof raw === 'object' && (raw.action || raw.question || raw.intent)) {
  data = raw;
} else {
  const text = coerceToString(raw);
  try {
    data = JSON.parse(text);
  } catch (e) {
    data = { action: 'ask_question', question: fallbackQuestion };
  }
}

let intent = (data.intent || '').toString().trim();
if (intent === 'insufficient_info') intent = 'insufficient_context';

const caseData = $node['Fetch Case'].json || {};
const transcript = ($node['Fetch Transcript'].json?.messages || []).slice(-40);

const caseStatus = String(caseData.status || '').trim().toLowerCase();
const proofRequirements = caseData.proof_requirements || {};
const proofUploads = Array.isArray(caseData.proof_uploads) ? caseData.proof_uploads : [];
const evidenceBundle = caseData.evidence_bundle || {};
const invalidReasonCode = String(caseData.invalid_reason_code || '').trim().toLowerCase();

const mapIntakeMessageToSubtype = (msg) => {
  const t = String(msg || '').toLowerCase();
  if (t.includes('damaged')) return 'damaged_goods';
  if (t.includes('wrong item')) return 'wrong_item';
  if (t.includes('missing') || t.includes('partial')) return 'partial_fulfillment';
  if (t.includes('package never arrived')) return 'package_never_arrived';
  if (t.includes('delivery is late')) return 'delivery_late';
  if (t.includes('wrong delivery address')) return 'wrong_delivery_address';
  if (t.includes('duplicate charge')) return 'duplicate_charge';
  if (t.includes('return')) return 'return_for_refund';
  return '';
};

const subtype = String(
  caseData.dispute_subtype ||
  caseData.disputeSubtype ||
  mapIntakeMessageToSubtype(caseData.intake_message)
).toLowerCase();

const normalizeQuestion = (q) =>
  String(q || '')
    .toLowerCase()
    .replace(/[^\w\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

const isGenericIssueQuestion = (q) => {
  const t = normalizeQuestion(q);
  return (
    t.includes('what issue are you experiencing') ||
    t.includes('what issue are you having') ||
    t.includes('what type of problem are you experiencing') ||
    t.includes('what type of issue are you experiencing') ||
    t.includes('what happened with your order') ||
    t.includes('tell me what happened') ||
    t.includes('could you share a bit more detail about what happened with your order')
  );
};

const isScopeQuestion = (q) => {
  const t = normalizeQuestion(q);
  return (
    (t.includes('all items affected') && t.includes('only some items')) ||
    t.includes('all items or only some items') ||
    t.includes('all or some items')
  );
};

const isItemQuestion = (q) => {
  const t = normalizeQuestion(q);
  return (
    (t.includes('what items') || t.includes('which items') || t.includes('what item') || t.includes('which item')) &&
    (t.includes('damaged') || t.includes('missing') || t.includes('wrong') || t.includes('affected'))
  );
};

const isDamageDetailQuestion = (q) => {
  const t = normalizeQuestion(q);
  return (
    t.includes('what type of damage occurred to the items') ||
    t.includes('what type of damage occurred') ||
    t.includes('what damage occurred') ||
    t.includes('describe the damage') ||
    t.includes('what kind of damage')
  );
};

const aiTexts = transcript
  .filter((m) => m.sender_type === 'ai' || m.sender_type === 'agent')
  .map((m) => String(m.content || '').toLowerCase());

const customerMessages = transcript
  .filter((m) => m.sender_type === 'customer')
  .map((m) => String(m.content || ''));

const customerText = customerMessages.join(' ').toLowerCase();

const latestCustomerMessage =
  [...transcript]
    .reverse()
    .find((m) => m.sender_type === 'customer') || null;

const latestCustomerMetadata =
  latestCustomerMessage && typeof latestCustomerMessage.metadata === 'object'
    ? latestCustomerMessage.metadata
    : null;

const latestCustomerUploadedProof =
  latestCustomerMetadata &&
  (
    latestCustomerMetadata.action === 'proof_uploaded' ||
    latestCustomerMetadata.role === 'proof_upload' ||
    Array.isArray(latestCustomerMetadata.attachments)
  );

const latestCustomerAppealed =
  latestCustomerMetadata &&
  latestCustomerMetadata.action === 'appeal_requested';

const hasAskedScope = aiTexts.some((t) => isScopeQuestion(t));
const hasAskedItemSelection = aiTexts.some((t) => isItemQuestion(t));
const hasAskedDamageDetail = aiTexts.some((t) => isDamageDetailQuestion(t));

const customerIndicatesOnlySome =
  /\bonly some\b|\bsome items\b|\bpart of\b|\bsubset\b|\ba few\b|\bone of\b|\bnot all\b/i.test(customerText);

const customerIndicatesAllItems =
  /\ball items\b|\bentire order\b|\bwhole order\b|\beverything\b|\ball of them\b|\bthe whole thing\b/i.test(customerText);

const customerProvidedItemAnswer =
  /damaged items:|missing items:|affected items:|wrong items:|items:/i.test(customerText);

const customerProvidedDamageDetail =
  /\bscratched\b|\bbroken\b|\bcracked\b|\bleaking\b|\btorn\b|\bdented\b|\bdefective\b|\bwet\b|\bshattered\b|\bspilled\b|\bripped\b|\bbent\b|\bpackaging damaged\b|\bbox damaged\b|\bitem itself is damaged\b|\bboth the item and packaging are damaged\b|\bonly the packaging is damaged\b/i.test(customerText);

const requiresScopeFlow = ['damaged_goods', 'wrong_item', 'partial_fulfillment'].includes(subtype);
const requiresDamageDetail = subtype === 'damaged_goods';

const scopeResolved = !requiresScopeFlow || customerIndicatesOnlySome || customerIndicatesAllItems;
const itemSelectionResolved = !requiresScopeFlow || !customerIndicatesOnlySome || customerProvidedItemAnswer;
const damageDetailResolved = !requiresDamageDetail || customerProvidedDamageDetail;

const allRequiredSlotsResolved =
  scopeResolved &&
  itemSelectionResolved &&
  damageDetailResolved;

const proofRequired =
  proofRequirements?.required === true ||
  ['damaged_goods', 'wrong_item', 'not_as_described', 'partial_fulfillment'].includes(subtype);

const proofAlreadyPresent =
  proofUploads.length > 0 ||
  evidenceBundle?.proof_present === true ||
  (Array.isArray(evidenceBundle?.proof_uploads) && evidenceBundle.proof_uploads.length > 0);

let next_action = 'error';
let question = data.question || null;

if (isGenericIssueQuestion(question) && subtype) {
  question = null;
}

const lastAiQuestion =
  [...transcript]
    .reverse()
    .find((m) => (m.sender_type === 'ai' || m.sender_type === 'agent') && typeof m.content === 'string')
    ?.content || '';

const pickNextQuestion = () => {
  if (!scopeResolved && requiresScopeFlow) {
    return 'Are all items affected, or only some items?';
  }

  if (!itemSelectionResolved && requiresScopeFlow && customerIndicatesOnlySome) {
    return 'Which items are affected?';
  }

  if (!damageDetailResolved && requiresDamageDetail) {
    return 'What type of damage occurred to the items?';
  }

  return null;
};

// -----------------------------------------------------------------------------
// STATE-FIRST ROUTING
// -----------------------------------------------------------------------------

if (caseStatus === 'awaiting_customer_decision') {
  next_action = 'await_customer_decision';
  question = null;
  return [{
    next_action,
    question,
    intent: null,
    intent_summary: invalidReasonCode
      ? `Case is awaiting customer decision due to ${invalidReasonCode}.`
      : 'Case is awaiting customer decision.',
  }];
}

if (caseStatus === 'awaiting_customer_proof') {
  if (proofAlreadyPresent || latestCustomerUploadedProof) {
    if (allRequiredSlotsResolved) {
      next_action = 'classify_intent';
      intent = intent || 'valid_dispute';
      question = null;
      if (!data.intent_summary) {
        data.intent_summary = 'Required proof is present and intake context is sufficient for triage.';
      }
    } else {
      const requiredNext = pickNextQuestion();
      if (requiredNext) {
        next_action = 'ask_question';
        question = requiredNext;
      } else {
        next_action = 'classify_intent';
        intent = intent || 'valid_dispute';
        question = null;
        if (!data.intent_summary) {
          data.intent_summary = 'Required proof is present and intake context is sufficient for triage.';
        }
      }
    }
  } else {
    next_action = 'ask_for_proof';
    question = proofRequestQuestion;
  }

  return [{
    next_action,
    question,
    intent: next_action === 'classify_intent' ? (intent || 'valid_dispute') : null,
    intent_summary: data.intent_summary || null,
  }];
}

// -----------------------------------------------------------------------------
// NORMAL INTAKE ROUTING
// -----------------------------------------------------------------------------

if (proofRequired && !proofAlreadyPresent && data.action === 'ask_for_proof') {
  next_action = 'ask_for_proof';
  question = question || proofRequestQuestion;
} else if (allRequiredSlotsResolved) {
  next_action = 'classify_intent';
  intent = intent || 'valid_dispute';
  question = null;
  if (!data.intent_summary) {
    data.intent_summary = 'Customer provided sufficient intake context for triage.';
  }
} else if (data.action === 'ask_question') {
  next_action = 'ask_question';
  question = question || pickNextQuestion() || fallbackQuestion;
} else if (data.action === 'ask_for_proof') {
  next_action = proofRequired && !proofAlreadyPresent ? 'ask_for_proof' : 'ask_question';
  question = next_action === 'ask_for_proof'
    ? (question || proofRequestQuestion)
    : (pickNextQuestion() || fallbackQuestion);
} else if (data.action === 'classify_intent') {
  if (intent === 'valid_dispute') {
    const requiredNext = pickNextQuestion();
    if (requiredNext) {
      next_action = 'ask_question';
      question = requiredNext;
    } else if (proofRequired && !proofAlreadyPresent) {
      next_action = 'ask_for_proof';
      question = proofRequestQuestion;
    } else {
      next_action = 'classify_intent';
    }
  } else if (intent === 'insufficient_context') {
    next_action = 'ask_question';
    question = question || pickNextQuestion() || fallbackQuestion;
  } else {
    next_action = 'ask_question';
    question = question || pickNextQuestion() || fallbackQuestion;
  }
} else if (data.action === 'await_customer_decision') {
  next_action = 'await_customer_decision';
  question = null;
} else {
  if (proofRequired && !proofAlreadyPresent) {
    next_action = 'ask_for_proof';
    question = proofRequestQuestion;
  } else {
    next_action = 'ask_question';
    question = pickNextQuestion() || fallbackQuestion;
  }
}

// Never regress backward in sequence for normal intake questions
if (next_action === 'ask_question') {
  if (isScopeQuestion(question) && scopeResolved) {
    question = pickNextQuestion();
  }

  if (isItemQuestion(question) && itemSelectionResolved) {
    question = pickNextQuestion();
  }

  if (isDamageDetailQuestion(question) && damageDetailResolved) {
    question = pickNextQuestion();
  }
}

if (next_action === 'ask_question' && !question && allRequiredSlotsResolved) {
  if (proofRequired && !proofAlreadyPresent) {
    next_action = 'ask_for_proof';
    question = proofRequestQuestion;
  } else {
    next_action = 'classify_intent';
    intent = intent || 'valid_dispute';
    question = null;
    if (!data.intent_summary) {
      data.intent_summary = 'Customer provided sufficient intake context for triage.';
    }
  }
}

// Stop same-question loops
if (
  (next_action === 'ask_question' || next_action === 'ask_for_proof') &&
  question &&
  normalizeQuestion(question) === normalizeQuestion(lastAiQuestion)
) {
  const requiredNext = pickNextQuestion();

  if (next_action === 'ask_for_proof') {
    next_action = proofAlreadyPresent ? 'classify_intent' : 'ask_for_proof';
    question = proofAlreadyPresent ? null : proofRequestQuestion;
  } else if (requiredNext && normalizeQuestion(requiredNext) !== normalizeQuestion(question)) {
    question = requiredNext;
  } else if (allRequiredSlotsResolved && (!proofRequired || proofAlreadyPresent)) {
    next_action = 'classify_intent';
    intent = intent || 'valid_dispute';
    question = null;
    if (!data.intent_summary) {
      data.intent_summary = 'Customer provided sufficient intake context for triage.';
    }
  } else if (proofRequired && !proofAlreadyPresent) {
    next_action = 'ask_for_proof';
    question = proofRequestQuestion;
  } else {
    next_action = 'classify_intent';
    intent = intent || 'valid_dispute';
    question = null;
    if (!data.intent_summary) {
      data.intent_summary = 'Sufficient intake context collected for triage classification.';
    }
  }
}

return [{
  next_action,
  question,
  intent: next_action === 'classify_intent' ? (intent || null) : null,
  intent_summary: data.intent_summary || null,
}];

